CREATE TABLE IF NOT EXISTS users (user_id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, username VARCHAR(100) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, role VARCHAR(20) DEFAULT 'user', branch VARCHAR(100), status VARCHAR(20) DEFAULT 'active', created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS products (product_id VARCHAR(50) PRIMARY KEY, product_name VARCHAR(255) NOT NULL, unit VARCHAR(50), is_active BOOLEAN DEFAULT true, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS stock (product_id VARCHAR(50) PRIMARY KEY REFERENCES products(product_id), qty_on_hand NUMERIC(10,2) DEFAULT 0, updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS receive_header (receive_id SERIAL PRIMARY KEY, receive_no VARCHAR(50) UNIQUE, receive_date DATE, vendor_name VARCHAR(255), buyer_name VARCHAR(255), ref_no VARCHAR(100), note TEXT, total_amount NUMERIC(12,2) DEFAULT 0, created_by VARCHAR(100), created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS receive_items (receive_item_id SERIAL PRIMARY KEY, receive_id INTEGER REFERENCES receive_header(receive_id), receive_no VARCHAR(50), line_no INTEGER, product_id VARCHAR(50), product_name VARCHAR(255), unit VARCHAR(50), qty NUMERIC(10,2) DEFAULT 0, unit_price NUMERIC(12,2) DEFAULT 0, amount NUMERIC(12,2) DEFAULT 0, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS issue_header (issue_no VARCHAR(50) PRIMARY KEY, issue_date DATE NOT NULL, requester_name VARCHAR(255), issue_branch VARCHAR(100), total_qty NUMERIC(10,2) DEFAULT 0, note TEXT, created_by VARCHAR(100), updated_by VARCHAR(100), created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS issue_items (issue_item_id SERIAL PRIMARY KEY, issue_no VARCHAR(50) REFERENCES issue_header(issue_no) ON DELETE CASCADE, line_no INTEGER, product_id VARCHAR(50), product_name VARCHAR(255), unit VARCHAR(50), qty_issue NUMERIC(10,2) DEFAULT 0, qty_on_hand NUMERIC(10,2), created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS unit_conversions (conversion_id SERIAL PRIMARY KEY, conversion_no VARCHAR(50) UNIQUE, conversion_date DATE NOT NULL, source_product_id VARCHAR(50), source_product_name VARCHAR(255), source_unit VARCHAR(50), source_qty NUMERIC(10,2), source_cost_per_unit NUMERIC(12,4), target_product_id VARCHAR(50), target_product_name VARCHAR(255), target_unit VARCHAR(50), target_qty NUMERIC(10,2), target_cost_per_unit NUMERIC(12,4), note TEXT, created_by VARCHAR(100), created_at TIMESTAMP DEFAULT NOW());

