  const values = items.map((item, i) =>
    `(${body.receive_id || 0}, '${receiveNo}', ${i + 1}, '${(item.product_id || '').replace(/'/g, "''")}', '${(item.product_name || '').replace(/'/g, "''")}', '${(item.unit || '').replace(/'/g, "''")}', ${parseFloat(item.qty) || 0}, ${parseFloat(item.unit_price) || 0}, ${parseFloat(item.amount) || 0})`
  ).join(',');
  insertItemsSql = `INSERT INTO receive_items (receive_id, receive_no, line_no, product_id, product_name, unit, qty, unit_price, amount) VALUES ${values};`;
}

const updateStockSql = items.map(item =>
  `INSERT INTO stock (product_id, qty_on_hand) VALUES ('${(item.product_id || '').replace(/'/g, "''")}', ${parseFloat(item.qty) || 0}) ON CONFLICT (product_id) DO UPDATE SET qty_on_hand = stock.qty_on_hand + ${parseFloat(item.qty) || 0}, updated_at = NOW();`
).join('\n');

const sql = `INSERT INTO receive_header (receive_no, receive_date, vendor_name, buyer_name, ref_no, note, total_amount, created_by)
VALUES ('${receiveNo}', '${receiveDate}', '${(body.vendor_name || '').replace(/'/g, "''")}', '${(body.buyer_name || '').replace(/'/g, "''")}', '${(body.ref_no || '').replace(/'/g, "''")}', '${(body.note || '').replace(/'/g, "''")}', ${parseFloat(body.total_amount) || 0}, '${(body.created_by || '').replace(/'/g, "''")}') RETURNING receive_id, receive_no;
${insertItemsSql}
${updateStockSql}`;

return [{ json: { sql, receive_no: receiveNo } }];

