const ocr = $input.first().json;
const markdown = (ocr.pages && ocr.pages[0] && ocr.pages[0].markdown) ? ocr.pages[0].markdown : 'ไม่พบข้อความ';
const systemPrompt = "คุณคือผู้ช่วยแปลง OCR จากใบส่งสินค้าภาษาไทยให้เป็น JSON\nกติกา: ตอบ JSON เท่านั้น ห้าม markdown ห้ามคำอธิบาย ถ้าไม่พบใช้ null วันที่รูปแบบ YYYY-MM-DD ตัวเลขเป็น number\nโครงสร้าง JSON: {\"seller\":{\"name_th\":null,\"name_en\":null,\"tax_id\":null,\"address_th\":null,\"tel\":null},\"buyer\":{\"name\":null,\"tax_id\":null,\"branch\":null,\"address\":null},\"ship_to\":{\"customer_code\":null,\"name\":null,\"address\":null},\"document\":{\"doc_no\":null,\"date\":null,\"payment_type\":null,\"credit_term\":null,\"due_date\":null,\"so_no\":null},\"items\":[{\"item_no\":1,\"code\":null,\"description_raw\":null,\"description_clean\":null,\"quantity\":null,\"unit\":null,\"unit_price\":null,\"net_amount\":null,\"quantity_inferred\":false}]}";
return [{ json: { model: 'gpt-4.1-mini', messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: markdown }] } }];

const resp = $input.first().json;
const content = resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
if (!content) return [{ json: { success: false, error: 'No response from OpenAI', items: [] } }];
let parsed;
try {
  let clean = content.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  return [{ json: { success: false, error: 'JSON parse failed', raw: content, items: [] } }];
}
function T(v) { return (v ?? '').toString().trim(); }
function N(v) {
  if (v == null || v === '') return null;
  const n = Number(String(v).replace(/,/g,'').trim());
  return Number.isFinite(n) ? n : null;
}
const items = Array.isArray(parsed.items) ? parsed.items.map((r, i) => ({
  item_no: N(r.item_no) ?? (i + 1),
  code: T(r.code) || null,
  description_raw: T(r.description_raw) || null,
  description_clean: T(r.description_clean) || null,
  quantity: N(r.quantity),
  unit: T(r.unit) || null,
  unit_price: N(r.unit_price),
  net_amount: N(r.net_amount),
  quantity_inferred: !!r.quantity_inferred
})) : [];
return [{ json: { success: true, seller: parsed.seller || {}, buyer: parsed.buyer || {}, ship_to: parsed.ship_to || {}, document: parsed.document || {}, items } }];

const ocr = $('Code Normalize OCR').first().json;
const rows = $input.all().map(x => x.json);
function T(v) { return (v ?? '').toString().trim(); }
function N(v) {
  if (v == null || v === '') return 0;
  const n = Number(String(v).replace(/,/g,'').trim());
  return Number.isFinite(n) ? n : 0;
}
function normCode(s) { return T(s).replace(/[\s\-_.\/]/g,'').toUpperCase(); }
function normName(s) {
  let x = T(s).toLowerCase();
  x = x.replace(/\(.*?\)/g,' ').replace(/\b\d+(\.\d+)?\b/g,' ');
  x = x.replace(/\u0e19\u0e34\u0e49\u0e27|\u0e01\u0e23\u0e31\u0e21|\u0e01\u0e01\.?|kg|ml|\u0e21\u0e25\.?|\u0e25\u0e34\u0e15\u0e23|\u0e41\u0e1e\u0e47\u0e04|\u0e01\u0e25\u0e48\u0e2d\u0e07|\u0e23\u0e35\u0e21|\u0e2d\u0e31\u0e19|\u0e14\u0e49\u0e32\u0e21|\u0e16\u0e38\u0e07|\u0e0b\u0e2d\u0e07|\u0e02\u0e27\u0e14|\u0e41\u0e01\u0e25\u0e25\u0e2d\u0e19|\u0e0a\u0e38\u0e14|\u0e41\u0e1c\u0e48\u0e19|\u0e41\u0e17\u0e48\u0e07|\u0e04\u0e39\u0e48|\u0e42\u0e2b\u0e25/gi,' ');
  return x.replace(/\s+/g,' ').trim();
}
const products = rows.map(r => ({
  product_id: T(r.product_id), product_name: T(r.product_name),
  product_code: T(r.product_code), product_code_norm: normCode(r.product_code),
  unit: T(r.unit), product_group: T(r.product_group),
  norm_name: normName(r.product_name)
})).filter(p => p.product_id && p.product_name);
const byCode = new Map(products.filter(p => p.product_code_norm).map(p => [p.product_code_norm, p]));
const byName = new Map(products.filter(p => p.norm_name).map(p => [p.norm_name, p]));
function matchProduct(item) {
  const codeNorm = normCode(T(item.code));
  const nameNorm = normName(T(item.description_clean || item.description_raw || ''));
  const unit = T(item.unit);
  if (codeNorm && byCode.has(codeNorm)) { const p = byCode.get(codeNorm); return {...p, match_status:'MATCHED', match_score:1.0, matched_by:'product_code', unit: p.unit || unit}; }
  if (nameNorm && byName.has(nameNorm)) { const p = byName.get(nameNorm); return {...p, match_status:'MATCHED', match_score:0.95, matched_by:'name_exact', unit: p.unit || unit}; }
  const found = products.find(p => p.norm_name && nameNorm && (nameNorm.includes(p.norm_name) || p.norm_name.includes(nameNorm)));
  if (found) return {...found, match_status:'MATCHED', match_score:0.85, matched_by:'name_contains', unit: found.unit || unit};
  return {product_id:'', product_name:'', product_group:'', unit, match_status:'UNMATCHED', match_score:0, matched_by:''};
}
const doc = ocr.document || {};
const ocrItems = Array.isArray(ocr.items) ? ocr.items : [];
const matchedItems = ocrItems.map((r, idx) => {
  const m = matchProduct(r);
  const qty = N(r.quantity);
  const unitPrice = N(r.unit_price);
  const amount = (r.net_amount != null && r.net_amount !== '') ? N(r.net_amount) : qty * unitPrice;
  return {
    line_no: idx + 1,
    product_code: T(r.code),
    product_name_from_ocr: T(r.description_clean || r.description_raw || ''),
    product_id: m.product_id, product_name: m.product_name, product_group: m.product_group,
    qty, unit: m.unit || T(r.unit), unit_price: unitPrice, amount,
    quantity_inferred: !!r.quantity_inferred,
    match_status: m.match_status, match_score: m.match_score, matched_by: m.matched_by, remark: ''
  };
});
const seller = ocr.seller || {};
const buyer = ocr.buyer || {};
const ship_to = ocr.ship_to || {};
return [{ json: {
  success: true,
  header: {
    receive_no: T(doc.doc_no), receive_date: T(doc.date),
    vendor_name: T(seller.name_th || seller.name_en || ''),
    vendor_tax_id: T(seller.tax_id || ''),
    vendor_address: T(seller.address_th || seller.address_en || ''),
    buyer_name: T(buyer.name || ''), buyer_tax_id: T(buyer.tax_id || ''),
    buyer_branch: T(buyer.branch || ''), buyer_address: T(buyer.address || ''),
    ship_to_code: T(ship_to.customer_code || ''), ship_to_name: T(ship_to.name || ''),
    payment_type: T(doc.payment_type || ''), credit_term: N(doc.credit_term),
    due_date: T(doc.due_date || ''), so_no: T(doc.so_no || ''),
    created_by: '', remark: ''
  },
  items: matchedItems,
  products_master: products,
  summary: {
    item_count: matchedItems.length,
    matched_count: matchedItems.filter(r => r.match_status === 'MATCHED').length,
    unmatched_count: matchedItems.filter(r => r.match_status !== 'MATCHED').length,
    product_count: products.length
  }
}}];

const body = $input.first().json.body;
const convNo = 'CNV-' + Date.now();
const convDate = body.conversion_date || new Date().toISOString().split('T')[0];
const srcId = (body.source_product_id || '').replace(/'/g, "''");
const srcName = (body.source_product_name || '').replace(/'/g, "''");
const srcUnit = (body.source_unit || '').replace(/'/g, "''");
const srcQty = parseFloat(body.source_qty) || 0;
const srcCost = parseFloat(body.source_cost_per_unit) || 0;
const tgtId = (body.target_product_id || '').replace(/'/g, "''");
const tgtName = (body.target_product_name || '').replace(/'/g, "''");
const tgtUnit = (body.target_unit || '').replace(/'/g, "''");
const tgtQty = parseFloat(body.target_qty) || 0;
const tgtCost = srcQty > 0 && tgtQty > 0 ? Math.round((srcCost * srcQty / tgtQty) * 10000) / 10000 : 0;
const note = (body.note || '').replace(/'/g, "''");
const createdBy = (body.created_by || '').replace(/'/g, "''");

const sql = `INSERT INTO unit_conversions (conversion_no, conversion_date, source_product_id, source_product_name, source_unit, source_qty, source_cost_per_unit, target_product_id, target_product_name, target_unit, target_qty, target_cost_per_unit, note, created_by) VALUES ('${convNo}', '${convDate}', '${srcId}', '${srcName}', '${srcUnit}', ${srcQty}, ${srcCost}, '${tgtId}', '${tgtName}', '${tgtUnit}', ${tgtQty}, ${tgtCost}, '${note}', '${createdBy}');
UPDATE stock SET qty_on_hand = qty_on_hand - ${srcQty}, updated_at = NOW() WHERE product_id = '${srcId}';
INSERT INTO stock (product_id, qty_on_hand) VALUES ('${tgtId}', ${tgtQty}) ON CONFLICT (product_id) DO UPDATE SET qty_on_hand = stock.qty_on_hand + ${tgtQty}, updated_at = NOW();`;

return [{ json: { sql, conversion_no: convNo } }];
